package se.gustavkarlsson.chefgpt.api

import kotlinx.serialization.Serializable
import kotlin.time.Instant

/**
 * An event is something that has happened in a chat.
 */
@Serializable
sealed interface ApiEvent {
    val id: EventId
    val timestamp: Instant
}

/**
 * Events generated by the system
 */
@Serializable
sealed interface ApiSystemEvent : ApiEvent

/**
 * Events generated by an agent
 */
@Serializable
sealed interface ApiAgentEvent : ApiEvent

/**
 * Events generated by a user, typically as the result of an [ApiAction]
 */
@Serializable
sealed interface ApiUserEvent : ApiEvent

@Serializable
data class ApiAgentMessage(
    override val id: EventId,
    override val timestamp: Instant,
    val text: String,
) : ApiAgentEvent {
    init {
        require(text.isNotBlank()) {
            "Text must not be blank"
        }
    }
}

@Serializable
data class ApiAgentReasoning(
    override val id: EventId,
    override val timestamp: Instant,
    val text: String,
) : ApiAgentEvent {
    init {
        require(text.isNotBlank()) {
            "Text must not be blank"
        }
    }
}

@Serializable
data class ApiUserJoined(
    override val id: EventId,
    override val timestamp: Instant,
    val joinId: JoinId,
) : ApiSystemEvent

@Serializable
data class ApiUserMessage(
    override val id: EventId,
    override val timestamp: Instant,
    val text: String?,
    val imageUrl: ImageUrl? = null,
) : ApiUserEvent {
    init {
        require(text == null || text.isNotBlank()) {
            "Text must not be blank"
        }
        require(text != null || imageUrl != null) {
            "Message must contain text or imageUrl"
        }
    }
}
